import React, { useState, useEffect, useRef } from 'react';
import { X, Edit2, Lock, Sparkles, ChevronDown, Check, TrendingUp, TrendingDown, Minus, Star, Send, Eye, ChevronLeft, ChevronRight, Plus, Trash2, AlertTriangle, Save, CheckCircle2, BarChart2, MessageSquare, Clock, GitFork, ArrowRight, Image, RefreshCw, BadgeCheck, CornerDownLeft, AlertCircle } from 'lucide-react';

export interface QRowData {id: string;stem: string;type: string;status: string;blooms: string;difficulty: string;topic: string;owner: string;pbis: number | null;version: number;folder: string;options?: string[];correctAnswer?: number;tags?: string[];updatedAt?: string;usageCount?: number;}

const STATUS_CONFIG: Record<string, {color: string;bg: string;label: string;}> = {
  Active: { color: '#15803d', bg: '#dcfce7', label: 'Active' }, Ready: { color: '#15803d', bg: '#dcfce7', label: 'Ready' }, 'In Review': { color: '#92400e', bg: '#fef3c7', label: 'In Review' }, Flagged: { color: '#991b1b', bg: '#fee2e2', label: 'Flagged' }, Draft: { color: '#374151', bg: '#f3f4f6', label: 'Draft' }, Approved: { color: '#1d4ed8', bg: '#dbeafe', label: 'Approved' }, Locked: { color: '#374151', bg: '#f3f4f6', label: 'Locked' }, 'Update Available': { color: '#7c3aed', bg: '#f5f3ff', label: 'Update Available' }
};
const TYPE_LOCKED_STATUSES = ['In Review', 'Active', 'Approved', 'Locked'];
const BLOOMS = ['Remember', 'Understand', 'Apply', 'Analyze', 'Evaluate', 'Create'];
const DIFFS = ['Easy', 'Medium', 'Hard'];
const DIFF_COLOR: Record<string, string> = { Easy: '#15803d', Medium: '#92400e', Hard: '#991b1b' };
const DIFF_BG: Record<string, string> = { Easy: '#dcfce7', Medium: '#fef3c7', Hard: '#fee2e2' };
const USAGE = [{ course: 'PHARM-501', term: 'Fall 2025', correct: 72, pbis: 0.41, n: 87 }, { course: 'PHARM-501', term: 'Spring 2025', correct: 68, pbis: 0.38, n: 91 }, { course: 'PHARM-401', term: 'Fall 2024', correct: 61, pbis: 0.31, n: 74 }];
const AI_RESULTS: Record<string, string> = { analyze: 'Quality score: 8.4/10. P-Biserial trend positive (0.27 to 0.41). Distractor A at 8% is non-functional; recommend replacing with Atenolol.', improve: 'Suggested stem: A 52yo male with mild persistent asthma requires antihypertensives. Which beta-blocker has the highest b1 selectivity? Elevates Bloom level to Analyze.', predict: 'Predicted Fall 2026: Correct 74-76%. P-Bis 0.42-0.45 if stem revised. Est. time 1m 40s.', variants: 'Variant A (Remember): Name the cardioselective beta-blocker used in asthma. Variant B (Analyze): Compare metoprolol vs carvedilol for COPD+HF. Variant C (Evaluate): Justify your beta-blocker selection given this risk profile.' };
const TABS = ['Overview', 'Edit', 'Preview', 'Metrics', 'Versions', 'Comments', 'AI'] as const;
type Tab = typeof TABS[number];
function mkId() {return Math.random().toString(36).slice(2, 8);}
const CURRENT_ROLE: 'faculty' | 'hod' | 'admin' = 'faculty';

function StatusBadge({ status }: {status: string;}) {const cfg = STATUS_CONFIG[status] || { color: '#374151', bg: '#f3f4f6', label: status };return <span style={{ display: 'inline-flex', alignItems: 'center', gap: 5, padding: '3px 10px', borderRadius: 99, fontSize: 13, fontWeight: 500, color: cfg.color, background: cfg.bg }}><span style={{ width: 5, height: 5, borderRadius: '50%', background: cfg.color, flexShrink: 0 }} />{cfg.label}</span>;}

function PanelBanner({ msg, type, onDismiss }: {msg: string;type: 'success' | 'info' | 'warn' | 'error';onDismiss(): void;}) {useEffect(() => {const t = setTimeout(onDismiss, 4500);return () => clearTimeout(t);}, [onDismiss]);const cfg = { success: { bg: '#dcfce7', border: '#bbf7d0', color: '#15803d', icon: CheckCircle2 }, info: { bg: '#dbeafe', border: '#bfdbfe', color: '#1d4ed8', icon: AlertCircle }, warn: { bg: '#fef3c7', border: '#fde68a', color: '#92400e', icon: AlertTriangle }, error: { bg: '#fee2e2', border: '#fecaca', color: '#991b1b', icon: AlertTriangle } }[type];const Icon = cfg.icon;return <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '9px 14px', background: cfg.bg, borderBottom: '1px solid ' + cfg.border, flexShrink: 0 }}><Icon size={13} style={{ color: cfg.color, flexShrink: 0 }} /><span style={{ fontSize: 13, color: cfg.color, fontWeight: 500, flex: 1 }}>{msg}</span><button onClick={onDismiss} style={{ padding: 2, border: 'none', background: 'transparent', cursor: 'pointer', color: cfg.color, display: 'flex' }}><X size={12} /></button></div>;}

function ReturnModal({ qId, onSend, onCancel }: {qId: string;onSend(c: string): void;onCancel(): void;}) {const [comment, setComment] = useState('');const ref = useRef<HTMLTextAreaElement>(null);useEffect(() => {ref.current?.focus();}, []);return <div style={{ position: 'fixed', inset: 0, zIndex: 9500, display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'rgba(0,0,0,0.4)' }}><div style={{ width: 460, background: '#fff', borderRadius: 14, boxShadow: '0 24px 80px rgba(0,0,0,0.2)', overflow: 'hidden' }}><div style={{ padding: '18px 22px', borderBottom: '1px solid #e5e7eb', display: 'flex', alignItems: 'center', gap: 10 }}><CornerDownLeft size={16} style={{ color: '#d97706' }} /><h2 style={{ fontSize: 17, fontWeight: 600, color: '#111827', margin: 0, flex: 1 }}>Return for revision</h2><button onClick={onCancel} style={{ padding: 5, border: 'none', background: 'transparent', cursor: 'pointer', color: '#9ca3af', display: 'flex', borderRadius: 5 }}><X size={15} /></button></div><div style={{ padding: '18px 22px' }}><p style={{ fontSize: 13, color: '#6b7280', lineHeight: 1.6, marginBottom: 14 }}>This moves <strong style={{ color: '#111827' }}>{qId}</strong> back to Draft and notifies the author.</p><label style={{ display: 'block', fontSize: 13, fontWeight: 600, color: '#374151', marginBottom: 7 }}>Reason for return</label><textarea ref={ref} value={comment} onChange={(e) => setComment(e.target.value)} placeholder='e.g. Distractor B is implausible. Stem is ambiguous for Apply level...' rows={4} style={{ width: '100%', padding: '10px 12px', borderRadius: 8, border: '1.5px solid #d1d5db', fontSize: 14, outline: 'none', resize: 'vertical', fontFamily: 'inherit', lineHeight: 1.6, boxSizing: 'border-box', color: '#111827' }} onFocus={(e) => e.currentTarget.style.borderColor = '#7c3aed'} onBlur={(e) => e.currentTarget.style.borderColor = '#d1d5db'} /></div><div style={{ padding: '12px 22px', borderTop: '1px solid #e5e7eb', display: 'flex', gap: 9, justifyContent: 'flex-end', background: '#f9fafb' }}><button onClick={onCancel} style={{ padding: '9px 16px', borderRadius: 8, background: 'transparent', border: '1px solid #d1d5db', fontSize: 13, cursor: 'pointer', color: '#374151', fontFamily: 'inherit', fontWeight: 500 }}>Cancel</button><button onClick={() => {if (comment.trim()) onSend(comment.trim());}} disabled={!comment.trim()} style={{ padding: '9px 20px', borderRadius: 8, background: comment.trim() ? '#d97706' : '#e5e7eb', color: comment.trim() ? '#fff' : '#9ca3af', fontSize: 13, fontWeight: 600, border: 'none', cursor: comment.trim() ? 'pointer' : 'default', fontFamily: 'inherit', display: 'flex', alignItems: 'center', gap: 5 }}><CornerDownLeft size={13} />Return for revision</button></div></div></div>;}

function EndorseModal({ qId, onConfirm, onCancel }: {qId: string;onConfirm(): void;onCancel(): void;}) {return <div style={{ position: 'fixed', inset: 0, zIndex: 9500, display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'rgba(0,0,0,0.4)' }}><div style={{ width: 420, background: '#fff', borderRadius: 14, boxShadow: '0 24px 80px rgba(0,0,0,0.2)', padding: '28px' }}><div style={{ display: 'flex', alignItems: 'center', gap: 10, marginBottom: 12 }}><BadgeCheck size={20} style={{ color: '#1d4ed8' }} /><div style={{ fontSize: 17, fontWeight: 600, color: '#111827' }}>Endorse {qId} as canonical?</div></div><p style={{ fontSize: 13, color: '#6b7280', lineHeight: 1.6, marginBottom: 20 }}>Marks your department preferred version. Faculty will see it as recommended when building assessments.</p><div style={{ display: 'flex', gap: 9, justifyContent: 'flex-end' }}><button onClick={onCancel} style={{ padding: '9px 16px', borderRadius: 8, background: 'transparent', border: '1px solid #d1d5db', fontSize: 13, cursor: 'pointer', color: '#374151', fontFamily: 'inherit', fontWeight: 500 }}>Cancel</button><button onClick={onConfirm} style={{ padding: '9px 20px', borderRadius: 8, background: '#1d4ed8', color: '#fff', fontSize: 13, fontWeight: 600, border: 'none', cursor: 'pointer', fontFamily: 'inherit', display: 'flex', alignItems: 'center', gap: 5 }}><BadgeCheck size={13} />Endorse this version</button></div></div></div>;}

function VersionDiff({ q, onUpdate, onDismiss }: {q: QRowData;onUpdate(): void;onDismiss(): void;}) {const newStem = 'A 65yo female with reactive airway disease presents with new-onset hypertension. Which beta-blocker is most appropriate?';return <div style={{ borderRadius: 8, border: '1px solid #ddd6fe', background: '#faf5ff', padding: '14px', marginBottom: 14 }}><div style={{ display: 'flex', alignItems: 'center', gap: 7, marginBottom: 10 }}><RefreshCw size={13} style={{ color: '#7c3aed' }} /><span style={{ fontSize: 13, fontWeight: 600, color: '#5b21b6' }}>Newer version available (v{q.version + 1})</span><button onClick={onDismiss} style={{ marginLeft: 'auto', padding: 2, border: 'none', background: 'transparent', cursor: 'pointer', color: '#9ca3af', display: 'flex' }}><X size={12} /></button></div><div style={{ fontSize: 12, color: '#9ca3af', marginBottom: 5, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em' }}>What changed</div><div style={{ marginBottom: 8 }}><div style={{ fontSize: 11, color: '#9ca3af', marginBottom: 2 }}>Current stem</div><div style={{ fontSize: 13, color: '#374151', lineHeight: 1.6, padding: '7px 10px', background: '#fee2e2', borderRadius: 5, textDecoration: 'line-through', opacity: 0.7 }}>{q.stem}</div></div><div style={{ marginBottom: 12 }}><div style={{ fontSize: 11, color: '#9ca3af', marginBottom: 2 }}>Updated stem</div><div style={{ fontSize: 13, color: '#111827', lineHeight: 1.6, padding: '7px 10px', background: '#dcfce7', borderRadius: 5 }}>{newStem}</div></div><div style={{ display: 'flex', gap: 8 }}><button onClick={onUpdate} style={{ display: 'flex', alignItems: 'center', gap: 5, padding: '7px 14px', borderRadius: 7, background: '#7c3aed', color: '#fff', border: 'none', fontSize: 13, fontWeight: 600, cursor: 'pointer' }}><Check size={12} />Update to v{q.version + 1}</button><button onClick={onDismiss} style={{ padding: '7px 14px', borderRadius: 7, border: '1px solid #ddd6fe', background: 'transparent', fontSize: 13, cursor: 'pointer', color: '#7c3aed', fontWeight: 500 }}>Keep current</button></div></div>;}

function StudentPreview({ q }: {q: QRowData;}) {const [selected, setSelected] = useState<number | null>(null);const [submitted, setSubmitted] = useState(false);const isCorrect = selected === q.correctAnswer;return <div><div style={{ padding: '9px 12px', borderRadius: 8, background: '#f3f4f6', border: '1px solid #e5e7eb', marginBottom: 12, display: 'flex', alignItems: 'center', gap: 6 }}><Eye size={12} style={{ color: '#9ca3af' }} /><span style={{ fontSize: 12, color: '#6b7280' }}>Student-facing view. Answers are not recorded.</span></div><div style={{ borderRadius: 10, border: '1px solid #e5e7eb', background: '#fff', overflow: 'hidden' }}><div style={{ background: '#7c3aed', padding: '12px 16px', display: 'flex', alignItems: 'center' }}><span style={{ fontSize: 12, fontWeight: 600, color: 'rgba(255,255,255,0.7)' }}>Question 1</span><span style={{ marginLeft: 'auto', fontSize: 11, fontWeight: 600, color: 'rgba(255,255,255,0.6)', background: 'rgba(255,255,255,0.15)', padding: '2px 8px', borderRadius: 99 }}>{q.type}</span></div><div style={{ padding: '16px 16px 12px' }}><p style={{ fontSize: 15, color: '#111827', lineHeight: 1.7, marginBottom: 16 }}>{q.stem}</p>{(q.type === 'MCQ' || q.type === 'MSQ') && q.options && <div style={{ display: 'flex', flexDirection: 'column', gap: 7, marginBottom: 14 }}>{q.options.map((o, i) => {const isSel = selected === i;const isC = i === q.correctAnswer;const show = submitted;return <button key={i} onClick={() => {if (!submitted) setSelected(i);}} style={{ display: 'flex', alignItems: 'center', gap: 9, padding: '10px 13px', borderRadius: 8, border: '2px solid ' + (show ? isC ? '#16a34a' : isSel ? '#dc2626' : '#e5e7eb' : isSel ? '#7c3aed' : '#e5e7eb'), background: show ? isC ? '#f0fdf4' : isSel ? '#fef2f2' : '#fff' : isSel ? '#f5f3ff' : '#fff', cursor: submitted ? 'default' : 'pointer', textAlign: 'left' }}><div style={{ width: 17, height: 17, borderRadius: '50%', border: '2px solid ' + (show ? isC ? '#16a34a' : isSel ? '#dc2626' : '#d1d5db' : isSel ? '#7c3aed' : '#d1d5db'), background: show ? isC ? '#16a34a' : isSel ? '#dc2626' : 'transparent' : isSel ? '#7c3aed' : 'transparent', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>{(isSel || show && isC) && <div style={{ width: 5, height: 5, borderRadius: '50%', background: '#fff' }} />}</div><span style={{ fontSize: 13, color: '#111827', flex: 1 }}>{String.fromCharCode(65 + i)}) {o}</span>{show && isC && <span style={{ fontSize: 12, color: '#15803d', fontWeight: 600 }}>Correct</span>}{show && isSel && !isC && <span style={{ fontSize: 12, color: '#dc2626', fontWeight: 600 }}>Incorrect</span>}</button>;})}</div>}{q.type === 'TF' && <div style={{ display: 'flex', gap: 8, marginBottom: 14 }}>{['True', 'False'].map((v) => <button key={v} onClick={() => {if (!submitted) setSelected(v === 'True' ? 1 : 0);}} style={{ flex: 1, padding: '12px', borderRadius: 8, border: '2px solid ' + (selected != null && (v === 'True' && selected === 1 || v === 'False' && selected === 0) ? '#7c3aed' : '#e5e7eb'), background: selected != null && (v === 'True' && selected === 1 || v === 'False' && selected === 0) ? '#f5f3ff' : '#fff', cursor: submitted ? 'default' : 'pointer' }}><div style={{ fontSize: 14, fontWeight: 600, color: '#111827' }}>{v}</div></button>)}</div>}{(q.type === 'Essay' || q.type === 'Fill blank') && <textarea placeholder={q.type === 'Essay' ? 'Write your response...' : 'Type your answer...'} disabled={submitted} rows={q.type === 'Essay' ? 5 : 2} style={{ width: '100%', padding: '9px 11px', borderRadius: 7, border: '1px solid #e5e7eb', fontSize: 13, outline: 'none', resize: 'vertical', fontFamily: 'inherit', color: '#111827', boxSizing: 'border-box', marginBottom: 10 }} />}{!submitted ? <button onClick={() => {if (selected !== null || q.type === 'Essay' || q.type === 'Fill blank') setSubmitted(true);}} style={{ display: 'flex', alignItems: 'center', gap: 5, padding: '8px 16px', borderRadius: 7, background: '#7c3aed', color: '#fff', border: 'none', fontSize: 13, fontWeight: 600, cursor: 'pointer' }}><Check size={12} />Submit answer</button> : <div style={{ display: 'flex', alignItems: 'center', gap: 7, padding: '9px 12px', borderRadius: 8, background: isCorrect ? '#dcfce7' : '#fee2e2' }}>{isCorrect ? <CheckCircle2 size={13} style={{ color: '#15803d' }} /> : <X size={13} style={{ color: '#991b1b' }} />}<span style={{ fontSize: 13, fontWeight: 600, color: isCorrect ? '#15803d' : '#991b1b' }}>{isCorrect ? 'Correct!' : 'Incorrect.'}{!isCorrect && q.options && q.correctAnswer != null && ' Correct: ' + String.fromCharCode(65 + q.correctAnswer) + ') ' + q.options[q.correctAnswer]}</span><button onClick={() => {setSubmitted(false);setSelected(null);}} style={{ marginLeft: 'auto', fontSize: 12, color: isCorrect ? '#15803d' : '#991b1b', background: 'transparent', border: 'none', cursor: 'pointer', textDecoration: 'underline' }}>Reset</button></div>}</div></div></div>;}

const TYPE_GROUPS = [{ group: 'Objective', types: ['MCQ', 'MSQ', 'TF'] }, { group: 'Structured', types: ['Matching', 'Ordering', 'Fill blank'] }, { group: 'Open-ended', types: ['Essay'] }, { group: 'Visual', types: ['Hotspot', 'Case Study'] }];
function TypeDropdown({ value, onChange, locked }: {value: string;onChange(t: string): void;locked: boolean;}) {const [open, setOpen] = useState(false);return <div style={{ position: 'relative' }}><button onClick={() => !locked && setOpen((o) => !o)} disabled={locked} style={{ display: 'flex', alignItems: 'center', gap: 8, width: '100%', padding: '10px 13px', borderRadius: 8, border: '1.5px solid ' + (open ? '#7c3aed' : 'var(--border-control)'), background: locked ? 'var(--surface)' : 'var(--card)', cursor: locked ? 'not-allowed' : 'pointer', textAlign: 'left', opacity: locked ? 0.7 : 1 }}><span style={{ flex: 1, fontSize: 14, fontWeight: 500, color: 'var(--foreground)' }}>{value}</span>{locked ? <Lock size={13} style={{ color: 'var(--text3)', flexShrink: 0 }} /> : <ChevronDown size={14} style={{ color: 'var(--text3)', flexShrink: 0, transform: open ? 'rotate(180deg)' : 'none', transition: 'transform .15s' }} />}</button>{open && <><div onClick={() => setOpen(false)} style={{ position: 'fixed', inset: 0, zIndex: 9900 }} /><div style={{ position: 'absolute', top: 'calc(100% + 4px)', left: 0, right: 0, background: 'var(--card)', border: '1px solid var(--border)', borderRadius: 10, boxShadow: '0 8px 32px rgba(0,0,0,0.15)', zIndex: 9901, overflow: 'hidden', maxHeight: 280, overflowY: 'auto' }}>{TYPE_GROUPS.map((g) => <div key={g.group}><div style={{ padding: '6px 12px 3px', fontSize: 10, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.07em', color: 'var(--text3)', background: 'var(--surface)' }}>{g.group}</div>{g.types.map((t) => <button key={t} onClick={() => {onChange(t);setOpen(false);}} style={{ display: 'flex', alignItems: 'center', gap: 8, width: '100%', padding: '8px 12px', background: t === value ? '#f5f3ff' : 'transparent', border: 'none', cursor: 'pointer', textAlign: 'left', fontSize: 14, color: t === value ? '#7c3aed' : 'var(--foreground)', fontWeight: t === value ? 600 : 400, fontFamily: 'var(--font-ui)' }} onMouseEnter={(e) => e.currentTarget.style.background = t === value ? '#f5f3ff' : 'var(--surface2)'} onMouseLeave={(e) => e.currentTarget.style.background = t === value ? '#f5f3ff' : 'transparent'}>{t === value && <Check size={12} style={{ color: '#7c3aed', flexShrink: 0 }} />}{t}</button>)}</div>)}</div></>}</div>;}

interface Choice {id: string;text: string;correct: boolean;}
function ChoiceBuilder({ multi, choices, onChange }: {multi: boolean;choices: Choice[];onChange(c: Choice[]): void;}) {const toggle = (id: string) => onChange(multi ? choices.map((c) => c.id === id ? { ...c, correct: !c.correct } : c) : choices.map((c) => ({ ...c, correct: c.id === id })));return <div style={{ display: 'flex', flexDirection: 'column', gap: 7 }}><span style={{ fontSize: 12, color: 'var(--text3)' }}>{multi ? 'Mark all correct answers' : 'Mark one correct answer'}</span>{choices.map((c, i) => <div key={c.id} style={{ display: 'flex', alignItems: 'center', gap: 9, padding: '9px 12px', borderRadius: 7, border: '1.5px solid ' + (c.correct ? '#16a34a' : 'var(--border-control)'), background: c.correct ? '#f0fdf4' : 'var(--card)' }}><button onClick={() => toggle(c.id)} style={{ width: 17, height: 17, borderRadius: multi ? 3 : '50%', border: '2px solid ' + (c.correct ? '#16a34a' : 'var(--border-control)'), background: c.correct ? '#16a34a' : 'transparent', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', flexShrink: 0, padding: 0 }}>{c.correct && <Check size={9} style={{ color: '#fff' }} />}</button><span style={{ fontSize: 11, fontWeight: 700, color: 'var(--text3)', fontFamily: 'monospace', flexShrink: 0, width: 14 }}>{String.fromCharCode(65 + i)}</span><input value={c.text} onChange={(e) => onChange(choices.map((x) => x.id === c.id ? { ...x, text: e.target.value } : x))} placeholder={'Option ' + String.fromCharCode(65 + i)} style={{ flex: 1, fontSize: 13, background: 'transparent', border: 'none', outline: 'none', color: 'var(--foreground)', fontFamily: 'var(--font-ui)' }} />{choices.length > 2 && <button onClick={() => onChange(choices.filter((x) => x.id !== c.id))} style={{ padding: 2, border: 'none', background: 'transparent', cursor: 'pointer', color: 'var(--text3)', display: 'flex', flexShrink: 0 }}><X size={11} /></button>}</div>)}<button onClick={() => onChange([...choices, { id: mkId(), text: '', correct: false }])} style={{ display: 'flex', alignItems: 'center', gap: 4, padding: '6px 10px', fontSize: 12, color: 'var(--text3)', background: 'transparent', border: '1px dashed var(--border-control)', borderRadius: 5, cursor: 'pointer' }}><Plus size={11} />Add option</button></div>;}
function TFBuilder({ value, onChange }: {value: boolean | null;onChange(v: boolean): void;}) {return <div style={{ display: 'flex', gap: 8 }}>{([true, false] as const).map((v) => <button key={String(v)} onClick={() => onChange(v)} style={{ flex: 1, padding: '14px', borderRadius: 8, border: '2px solid ' + (value === v ? v ? '#16a34a' : '#dc2626' : 'var(--border-control)'), background: value === v ? v ? '#f0fdf4' : '#fef2f2' : 'var(--card)', cursor: 'pointer' }}><div style={{ fontSize: 14, fontWeight: 700, color: value === v ? v ? '#15803d' : '#991b1b' : 'var(--text3)' }}>{v ? 'True' : 'False'}</div></button>)}</div>;}
function MatchingBuilder({ pairs, onChange }: {pairs: {id: string;left: string;right: string;}[];onChange(p: {id: string;left: string;right: string;}[]): void;}) {return <div>{pairs.map((p, i) => <div key={p.id} style={{ display: 'grid', gridTemplateColumns: '1fr 20px 1fr 24px', gap: 7, alignItems: 'center', marginBottom: 7 }}><input value={p.left} onChange={(e) => onChange(pairs.map((x) => x.id === p.id ? { ...x, left: e.target.value } : x))} placeholder={'Premise ' + (i + 1)} style={{ padding: '7px 9px', borderRadius: 6, border: '1px solid var(--border-control)', fontSize: 13, outline: 'none', fontFamily: 'var(--font-ui)', color: 'var(--foreground)' }} /><ArrowRight size={12} style={{ color: 'var(--text3)', justifySelf: 'center' }} /><input value={p.right} onChange={(e) => onChange(pairs.map((x) => x.id === p.id ? { ...x, right: e.target.value } : x))} placeholder={'Response ' + (i + 1)} style={{ padding: '7px 9px', borderRadius: 6, border: '1px solid #bbf7d0', background: '#f0fdf4', fontSize: 13, outline: 'none', fontFamily: 'var(--font-ui)', color: 'var(--foreground)' }} />{pairs.length > 2 && <button onClick={() => onChange(pairs.filter((x) => x.id !== p.id))} style={{ padding: 3, border: 'none', background: 'transparent', cursor: 'pointer', color: 'var(--text3)', display: 'flex' }}><X size={12} /></button>}</div>)}<button onClick={() => onChange([...pairs, { id: mkId(), left: '', right: '' }])} style={{ display: 'flex', alignItems: 'center', gap: 4, padding: '6px 10px', fontSize: 12, color: 'var(--text3)', background: 'transparent', border: '1px dashed var(--border-control)', borderRadius: 5, cursor: 'pointer' }}><Plus size={11} />Add pair</button></div>;}
function OrderingBuilder({ items, onChange }: {items: {id: string;text: string;}[];onChange(i: {id: string;text: string;}[]): void;}) {return <div><p style={{ fontSize: 12, color: 'var(--text3)', marginBottom: 8 }}>Enter in correct order. Students see them shuffled.</p>{items.map((item, i) => <div key={item.id} style={{ display: 'flex', gap: 7, alignItems: 'center', marginBottom: 7 }}><div style={{ width: 20, height: 20, borderRadius: '50%', background: '#7c3aed', color: '#fff', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 11, fontWeight: 700, flexShrink: 0 }}>{i + 1}</div><input value={item.text} onChange={(e) => onChange(items.map((x) => x.id === item.id ? { ...x, text: e.target.value } : x))} placeholder={'Step ' + (i + 1)} style={{ flex: 1, padding: '7px 9px', borderRadius: 6, border: '1px solid var(--border-control)', fontSize: 13, outline: 'none', fontFamily: 'var(--font-ui)', color: 'var(--foreground)' }} />{items.length > 2 && <button onClick={() => onChange(items.filter((x) => x.id !== item.id))} style={{ padding: 3, border: 'none', background: 'transparent', cursor: 'pointer', color: 'var(--text3)', display: 'flex' }}><X size={12} /></button>}</div>)}<button onClick={() => onChange([...items, { id: mkId(), text: '' }])} style={{ display: 'flex', alignItems: 'center', gap: 4, padding: '6px 10px', fontSize: 12, color: 'var(--text3)', background: 'transparent', border: '1px dashed var(--border-control)', borderRadius: 5, cursor: 'pointer' }}><Plus size={11} />Add step</button></div>;}
function FillBlankBuilder({ blanks, onChange }: {blanks: {id: string;answer: string;}[];onChange(b: {id: string;answer: string;}[]): void;}) {return <div><p style={{ fontSize: 12, color: 'var(--text3)', marginBottom: 8 }}>Use ___ in your stem to mark blanks.</p>{blanks.map((b, i) => <div key={b.id} style={{ display: 'flex', gap: 7, alignItems: 'center', marginBottom: 7 }}><span style={{ fontSize: 12, color: 'var(--text3)', flexShrink: 0, minWidth: 46 }}>Blank {i + 1}</span><input value={b.answer} onChange={(e) => onChange(blanks.map((x) => x.id === b.id ? { ...x, answer: e.target.value } : x))} placeholder='Accepted answers, comma-separated' style={{ flex: 1, padding: '7px 9px', borderRadius: 6, border: '1px solid var(--border-control)', fontSize: 13, outline: 'none', fontFamily: 'var(--font-ui)', color: 'var(--foreground)' }} />{blanks.length > 1 && <button onClick={() => onChange(blanks.filter((x) => x.id !== b.id))} style={{ padding: 3, border: 'none', background: 'transparent', cursor: 'pointer', color: 'var(--text3)', display: 'flex' }}><X size={12} /></button>}</div>)}<button onClick={() => onChange([...blanks, { id: mkId(), answer: '' }])} style={{ display: 'flex', alignItems: 'center', gap: 4, padding: '6px 10px', fontSize: 12, color: 'var(--text3)', background: 'transparent', border: '1px dashed var(--border-control)', borderRadius: 5, cursor: 'pointer' }}><Plus size={11} />Add blank</button></div>;}
function EssayBuilder({ rubric, onChange }: {rubric: {id: string;criterion: string;max: number;}[];onChange(r: {id: string;criterion: string;max: number;}[]): void;}) {return <div>{rubric.map((row) => <div key={row.id} style={{ display: 'grid', gridTemplateColumns: '1fr 60px 24px', gap: 6, alignItems: 'center', marginBottom: 6 }}><input value={row.criterion} onChange={(e) => onChange(rubric.map((r) => r.id === row.id ? { ...r, criterion: e.target.value } : r))} placeholder='Criterion' style={{ padding: '7px 9px', borderRadius: 6, border: '1px solid var(--border-control)', fontSize: 13, outline: 'none', fontFamily: 'var(--font-ui)', color: 'var(--foreground)' }} /><input type='number' min={0} value={row.max} onChange={(e) => onChange(rubric.map((r) => r.id === row.id ? { ...r, max: parseInt(e.target.value) || 0 } : r))} style={{ padding: '7px 9px', borderRadius: 6, border: '1px solid var(--border-control)', fontSize: 13, outline: 'none', textAlign: 'right', fontFamily: 'var(--font-ui)', color: 'var(--foreground)' }} />{rubric.length > 1 && <button onClick={() => onChange(rubric.filter((r) => r.id !== row.id))} style={{ padding: 3, border: 'none', background: 'transparent', cursor: 'pointer', color: '#991b1b', display: 'flex' }}><Trash2 size={12} /></button>}</div>)}<div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginTop: 4 }}><button onClick={() => onChange([...rubric, { id: mkId(), criterion: '', max: 4 }])} style={{ display: 'flex', alignItems: 'center', gap: 4, padding: '6px 10px', fontSize: 12, color: 'var(--text3)', background: 'transparent', border: '1px dashed var(--border-control)', borderRadius: 5, cursor: 'pointer' }}><Plus size={11} />Add criterion</button><span style={{ fontSize: 12, color: 'var(--text3)' }}>Total: <strong>{rubric.reduce((s, r) => s + r.max, 0)} pts</strong></span></div></div>;}

function InlineEdit({ q, onSave }: {q: QRowData;onSave(msg: string): void;}) {const typeLocked = TYPE_LOCKED_STATUSES.includes(q.status);const [type, setType] = useState(q.type);const [stem, setStem] = useState(q.stem);const [blooms, setBlooms] = useState(q.blooms);const [diff, setDiff] = useState(q.difficulty);const [saving, setSaving] = useState(false);const [saved, setSaved] = useState(false);const [choices, setChoices] = useState<Choice[]>((q.options || ['Option A', 'Option B', 'Option C', 'Option D']).map((o, i) => ({ id: mkId(), text: o, correct: i === (q.correctAnswer ?? 0) })));const [tfAnswer, setTfAnswer] = useState<boolean | null>(null);const [pairs, setPairs] = useState([{ id: mkId(), left: '', right: '' }, { id: mkId(), left: '', right: '' }, { id: mkId(), left: '', right: '' }]);const [orderItems, setOrderItems] = useState([{ id: mkId(), text: '' }, { id: mkId(), text: '' }, { id: mkId(), text: '' }]);const [blanks, setBlanks] = useState([{ id: mkId(), answer: '' }]);const [rubric, setRubric] = useState([{ id: mkId(), criterion: 'Clinical reasoning', max: 4 }, { id: mkId(), criterion: 'Evidence-based justification', max: 3 }]);const handleSave = async () => {setSaving(true);await new Promise((r) => setTimeout(r, 700));setSaving(false);setSaved(true);setTimeout(() => setSaved(false), 3000);onSave('Saved as v' + (q.version + 1));};const isChoice = type === 'MCQ' || type === 'MSQ';if (q.status === 'Locked') return <div style={{ padding: '20px 0', textAlign: 'center' }}><Lock size={24} style={{ color: '#d1d5db', margin: '0 auto 10px', display: 'block' }} /><div style={{ fontSize: 14, fontWeight: 500, color: 'var(--text2)', marginBottom: 6 }}>Locked by HOD</div><div style={{ fontSize: 13, color: 'var(--text3)' }}>Contact your department head to unlock.</div></div>;return <div style={{ display: 'flex', flexDirection: 'column', gap: 0 }}><div style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '9px 12px', borderRadius: 8, background: '#fef9c3', border: '1px solid #fde047', marginBottom: 18, fontSize: 13, color: '#713f12' }}><AlertTriangle size={12} style={{ flexShrink: 0, color: '#ca8a04' }} />Saving creates <strong style={{ margin: '0 3px' }}>v{q.version + 1}</strong>. Original preserved in history.</div><div style={{ marginBottom: 18 }}><div style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--text3)', marginBottom: 7 }}>Question type</div>{typeLocked ? <div style={{ display: 'flex', alignItems: 'center', gap: 8, padding: '9px 12px', borderRadius: 7, border: '1px solid var(--border-control)', background: 'var(--surface)' }}><span style={{ fontSize: 14, fontWeight: 500, color: 'var(--foreground)', flex: 1 }}>{type}</span><span style={{ display: 'flex', alignItems: 'center', gap: 4, fontSize: 12, color: 'var(--text3)' }}><Lock size={11} />Locked</span></div> : <TypeDropdown value={type} onChange={setType} locked={false} />}</div><div style={{ marginBottom: 18 }}><div style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--text3)', marginBottom: 7 }}>Question stem</div><textarea value={stem} onChange={(e) => setStem(e.target.value)} rows={4} style={{ width: '100%', fontSize: 14, lineHeight: 1.7, color: 'var(--foreground)', background: 'var(--card)', border: '1px solid var(--border-control)', borderRadius: 8, padding: '10px 12px', outline: 'none', resize: 'vertical', fontFamily: 'var(--font-ui)', boxSizing: 'border-box' }} onFocus={(e) => e.currentTarget.style.borderColor = '#7c3aed'} onBlur={(e) => e.currentTarget.style.borderColor = 'var(--border-control)'} /></div><div style={{ marginBottom: 18 }}><div style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--text3)', marginBottom: 9 }}>Answer configuration</div><div style={{ padding: '12px', borderRadius: 8, background: 'var(--surface)', border: '1px solid var(--border)' }}>{isChoice && <ChoiceBuilder multi={type === 'MSQ'} choices={choices} onChange={setChoices} />}{type === 'TF' && <TFBuilder value={tfAnswer} onChange={setTfAnswer} />}{type === 'Matching' && <MatchingBuilder pairs={pairs} onChange={setPairs} />}{type === 'Ordering' && <OrderingBuilder items={orderItems} onChange={setOrderItems} />}{type === 'Fill blank' && <FillBlankBuilder blanks={blanks} onChange={setBlanks} />}{type === 'Essay' && <EssayBuilder rubric={rubric} onChange={setRubric} />}{type === 'Hotspot' && <div style={{ padding: '16px', textAlign: 'center', color: 'var(--text3)' }}><Image size={18} style={{ opacity: 0.2, margin: '0 auto 6px', display: 'block' }} /><button style={{ padding: '5px 11px', borderRadius: 5, border: '1px solid var(--border-control)', background: 'var(--card)', fontSize: 12, cursor: 'pointer', color: 'var(--text2)' }}>Upload image</button></div>}{type === 'Case Study' && <div style={{ padding: '16px', textAlign: 'center', color: 'var(--text3)' }}><button style={{ padding: '5px 11px', borderRadius: 5, border: '1px solid var(--border-control)', background: 'var(--card)', fontSize: 12, cursor: 'pointer', color: 'var(--text2)' }}>Open case editor</button></div>}</div></div><div style={{ marginBottom: 18 }}><div style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--text3)', marginBottom: 7 }}>Bloom level</div><div style={{ display: 'flex', flexWrap: 'wrap', gap: 5 }}>{BLOOMS.map((b) => <button key={b} onClick={() => setBlooms(b)} style={{ padding: '5px 11px', borderRadius: 99, fontSize: 12, fontWeight: blooms === b ? 600 : 400, border: '1.5px solid ' + (blooms === b ? 'var(--brand)' : 'var(--border-control)'), background: blooms === b ? 'var(--brand-tint)' : 'var(--card)', color: blooms === b ? 'var(--brand)' : 'var(--text2)', cursor: 'pointer' }}>{b}</button>)}</div></div><div style={{ marginBottom: 22 }}><div style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.06em', color: 'var(--text3)', marginBottom: 7 }}>Difficulty</div><div style={{ display: 'flex', gap: 7 }}>{DIFFS.map((d) => <button key={d} onClick={() => setDiff(d)} style={{ flex: 1, padding: '8px 0', borderRadius: 7, fontSize: 13, fontWeight: diff === d ? 700 : 400, border: '1.5px solid ' + (diff === d ? DIFF_COLOR[d] : 'var(--border-control)'), background: diff === d ? DIFF_BG[d] : 'var(--card)', color: diff === d ? DIFF_COLOR[d] : 'var(--text2)', cursor: 'pointer' }}>{d}</button>)}</div></div><div style={{ display: 'flex', gap: 7, paddingTop: 4, borderTop: '1px solid var(--border)' }}><button onClick={handleSave} disabled={saving} style={{ display: 'flex', alignItems: 'center', gap: 5, flex: 1, justifyContent: 'center', padding: '9px 0', borderRadius: 8, background: saved ? '#16a34a' : 'var(--foreground)', color: 'var(--card)', border: 'none', cursor: 'pointer', fontSize: 13, fontWeight: 600, transition: 'background 0.2s' }}>{saved ? <Check size={13} /> : saving ? <Sparkles size={13} /> : <Save size={13} />}{saved ? 'Saved v' + (q.version + 1) : saving ? 'Saving...' : 'Save changes'}</button><button style={{ display: 'flex', alignItems: 'center', gap: 5, padding: '9px 14px', borderRadius: 8, background: 'var(--surface)', border: '1px solid var(--border-control)', color: 'var(--text2)', cursor: 'pointer', fontSize: 13, fontWeight: 600 }}><Send size={12} />Submit</button></div></div>;}

function Avatar({ initials, size = 28 }: {initials: string;size?: number;}) {return <div style={{ width: size, height: size, borderRadius: '50%', background: 'var(--brand-tint)', border: '1px solid var(--brand-border)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: size <= 28 ? 10 : 12, fontWeight: 700, color: 'var(--brand)', flexShrink: 0 }}>{initials}</div>;}

export function QuestionRowPanel({ q, onClose, onEdit, allQuestionIds, onNavigate, allQuestions, onStatusChange }: {q: QRowData;onClose: () => void;onEdit: () => void;allQuestionIds?: string[];onNavigate?: (q: QRowData) => void;allQuestions?: QRowData[];onStatusChange?: (id: string, s: string) => void;}) {
  const [tab, setTab] = useState<Tab>('Overview');
  const [starred, setStarred] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<string | null>(null);
  const [aiMode, setAiMode] = useState('analyze');
  const [newComment, setNewComment] = useState('');
  const [comments, setComments] = useState([{ id: 1, author: 'Dr. Kim', initials: 'DK', date: 'Mar 15', text: 'Option C may confuse students who covered beta-2 agonists.', resolved: false }, { id: 2, author: 'Dr. Nguyen', initials: 'DN', date: 'Feb 20', text: 'Performs well in PHARM-501. Consider for EOR prep bank.', resolved: true }]);
  const [panelBanner, setPanelBanner] = useState<{msg: string;type: 'success' | 'info' | 'warn' | 'error';} | null>(null);
  const [showReturnModal, setShowReturnModal] = useState(false);
  const [showEndorseModal, setShowEndorseModal] = useState(false);
  const [endorsed, setEndorsed] = useState(false);
  const [showVersionDiff, setShowVersionDiff] = useState(q.status === 'Update Available');
  const [statusChangeOpen, setStatusChangeOpen] = useState(false);
  const navIds = allQuestionIds || [q.id];const navQs = allQuestions || [q];
  const idx = navIds.indexOf(q.id);const canPrev = idx > 0;const canNext = idx < navIds.length - 1;
  const goNext = () => {if (canNext && onNavigate && navQs[idx + 1]) onNavigate(navQs[idx + 1]);};
  const goPrev = () => {if (canPrev && onNavigate && navQs[idx - 1]) onNavigate(navQs[idx - 1]);};
  const notify = (msg: string, type: 'success' | 'info' | 'warn' | 'error' = 'success') => setPanelBanner({ msg, type });
  const runAI = async (mode: string) => {setAiLoading(true);setAiResult(null);await new Promise((r) => setTimeout(r, 1600));setAiResult(AI_RESULTS[mode] || 'Analysis complete.');setAiLoading(false);};
  useEffect(() => {if (tab === 'AI' && aiResult === null && !aiLoading) runAI('analyze');}, [tab]);
  const statusColor = (STATUS_CONFIG[q.status] || { color: '#374151' }).color;
  const isLocked = q.status === 'Locked';
  const isHOD = CURRENT_ROLE === 'hod' || CURRENT_ROLE === 'admin';
  const statusActions: Array<{label: string;to: string;variant?: 'danger';}> = q.status === 'Draft' || q.status === 'Ready' ? [{ label: 'Submit for review', to: 'In Review' }] : q.status === 'In Review' && isHOD ? [{ label: 'Approve', to: 'Active' }, { label: 'Return for revision', to: '__return' }] : q.status === 'In Review' ? [] : q.status === 'Flagged' ? [{ label: 'Submit for review', to: 'In Review' }, { label: 'Send to Draft', to: 'Draft', variant: 'danger' }] : q.status === 'Active' && isHOD ? [{ label: 'Lock for exam', to: 'Locked' }] : [];
  const handleStatusAction = (to: string) => {if (to === '__return') {setStatusChangeOpen(false);setShowReturnModal(true);return;};if (onStatusChange) {onStatusChange(q.id, to);notify(q.id + ' moved to ' + to);};setStatusChangeOpen(false);};
  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', overflow: 'hidden', background: 'var(--card)', fontFamily: 'var(--font-ui)', position: 'relative' }}>
      {showReturnModal && <ReturnModal qId={q.id} onCancel={() => setShowReturnModal(false)} onSend={(comment) => {setShowReturnModal(false);if (onStatusChange) onStatusChange(q.id, 'Draft');notify('Returned for revision. Comment sent to ' + q.owner);}} />}
      {showEndorseModal && <EndorseModal qId={q.id} onCancel={() => setShowEndorseModal(false)} onConfirm={() => {setShowEndorseModal(false);setEndorsed(true);notify(q.id + ' endorsed as department canonical version');}} />}
      {panelBanner && <PanelBanner msg={panelBanner.msg} type={panelBanner.type} onDismiss={() => setPanelBanner(null)} />}
      <div style={{ display: 'flex', alignItems: 'center', gap: 6, padding: '12px 14px', borderBottom: '1px solid var(--border)', flexShrink: 0, background: 'var(--surface)' }}>
        <button disabled={!canPrev} onClick={goPrev} style={{ width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', border: '1px solid var(--border-control)', borderRadius: 6, background: 'var(--card)', cursor: canPrev ? 'pointer' : 'default', color: 'var(--text3)', opacity: canPrev ? 1 : 0.3 }}><ChevronLeft size={14} /></button>
        <div style={{ flex: 1, minWidth: 0 }}><div style={{ display: 'flex', alignItems: 'center', gap: 7 }}><span style={{ fontSize: 13, fontFamily: 'monospace', fontWeight: 700, color: 'var(--text3)' }}>{q.id}</span><span style={{ width: 5, height: 5, borderRadius: '50%', background: statusColor, flexShrink: 0 }} /><span style={{ fontSize: 13, color: 'var(--text2)', fontWeight: 500 }}>{q.status}</span>{endorsed && <span style={{ display: 'inline-flex', alignItems: 'center', gap: 3, fontSize: 11, padding: '1px 7px', borderRadius: 99, background: '#dbeafe', color: '#1d4ed8', fontWeight: 600 }}><BadgeCheck size={10} />Endorsed</span>}<span style={{ fontSize: 12, color: 'var(--text3)', marginLeft: 2 }}>{idx + 1}/{navIds.length}</span></div></div>
        <button disabled={!canNext} onClick={goNext} style={{ width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', border: '1px solid var(--border-control)', borderRadius: 6, background: 'var(--card)', cursor: canNext ? 'pointer' : 'default', color: 'var(--text3)', opacity: canNext ? 1 : 0.3 }}><ChevronRight size={14} /></button>
        <div style={{ width: 1, height: 18, background: 'var(--border)', margin: '0 2px' }} />
        {([{ icon: Star, fn: () => setStarred((s) => !s), title: 'Star', active: starred }, { icon: Edit2, fn: () => setTab('Edit'), title: 'Edit', active: tab === 'Edit' }, { icon: GitFork, fn: () => {notify('Fork created: ' + q.id + '-fork');}, title: 'Fork' }, { icon: Eye, fn: () => setTab('Preview'), title: 'Student preview', active: tab === 'Preview' }, { icon: X, fn: onClose, title: 'Close' }] as any[]).map((b, i) => <button key={i} title={b.title} onClick={b.fn} style={{ width: 28, height: 28, display: 'flex', alignItems: 'center', justifyContent: 'center', border: 'none', borderRadius: 6, background: b.active ? 'var(--surface2)' : 'transparent', cursor: 'pointer', color: b.active ? 'var(--foreground)' : 'var(--text3)' }} onMouseEnter={(e) => e.currentTarget.style.background = 'var(--surface2)'} onMouseLeave={(e) => e.currentTarget.style.background = b.active ? 'var(--surface2)' : 'transparent'}><b.icon size={14} /></button>)}
      </div>
      {showVersionDiff && q.status === 'Update Available' && <div style={{ padding: '10px 14px', borderBottom: '1px solid var(--border)', flexShrink: 0 }}><VersionDiff q={q} onUpdate={() => {setShowVersionDiff(false);if (onStatusChange) onStatusChange(q.id, 'Active');notify(q.id + ' updated to v' + (q.version + 1));}} onDismiss={() => setShowVersionDiff(false)} /></div>}
      {statusActions.length > 0 && !isLocked && <div style={{ padding: '10px 14px', borderBottom: '1px solid var(--border)', flexShrink: 0 }}><div style={{ position: 'relative' }}><button onClick={() => setStatusChangeOpen((o) => !o)} style={{ display: 'flex', alignItems: 'center', gap: 8, width: '100%', padding: '8px 12px', borderRadius: 8, background: 'var(--surface)', border: '1px solid var(--border-control)', cursor: 'pointer', textAlign: 'left' }}><StatusBadge status={q.status} /><span style={{ flex: 1, fontSize: 13, color: 'var(--text2)' }}>Change status</span><ChevronDown size={13} style={{ color: 'var(--text3)', transform: statusChangeOpen ? 'rotate(180deg)' : 'none', transition: 'transform .15s' }} /></button>{statusChangeOpen && <><div onClick={() => setStatusChangeOpen(false)} style={{ position: 'fixed', inset: 0, zIndex: 400 }} /><div style={{ position: 'absolute', top: 'calc(100% + 4px)', left: 0, right: 0, background: 'var(--card)', border: '1px solid var(--border)', borderRadius: 8, boxShadow: '0 6px 20px rgba(0,0,0,0.12)', zIndex: 401, padding: 4 }}>{statusActions.map((a) => <button key={a.to} onClick={() => handleStatusAction(a.to)} style={{ display: 'flex', alignItems: 'center', gap: 8, width: '100%', padding: '9px 12px', fontSize: 13, background: 'transparent', border: 'none', borderRadius: 6, cursor: 'pointer', color: a.variant === 'danger' ? '#991b1b' : 'var(--foreground)', textAlign: 'left' }} onMouseEnter={(e) => e.currentTarget.style.background = a.variant === 'danger' ? '#fef2f2' : 'var(--surface2)'} onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}>{a.to === '__return' ? <CornerDownLeft size={13} style={{ color: '#d97706', flexShrink: 0 }} /> : <span style={{ width: 7, height: 7, borderRadius: '50%', background: (STATUS_CONFIG[a.to] || { color: '#374151' }).color, flexShrink: 0 }} />}{a.label}</button>)}</div></>}</div></div>}
      {isLocked && <div style={{ padding: '10px 14px', borderBottom: '1px solid var(--border)', flexShrink: 0 }}><div style={{ display: 'flex', alignItems: 'center', gap: 7, padding: '8px 12px', borderRadius: 8, background: '#f3f4f6', border: '1px solid #e5e7eb' }}><Lock size={13} style={{ color: '#9ca3af' }} /><span style={{ fontSize: 13, color: '#374151', fontWeight: 500 }}>Locked by HOD during active exam window</span></div></div>}
      {isHOD && (q.status === 'Active' || q.status === 'Approved') && !endorsed && <div style={{ padding: '8px 14px', borderBottom: '1px solid var(--border)', flexShrink: 0 }}><button onClick={() => setShowEndorseModal(true)} style={{ display: 'flex', alignItems: 'center', gap: 6, width: '100%', padding: '7px 12px', borderRadius: 7, border: '1px solid #bfdbfe', background: '#eff6ff', cursor: 'pointer', fontSize: 13, color: '#1d4ed8', fontWeight: 500 }} onMouseEnter={(e) => e.currentTarget.style.background = '#dbeafe'} onMouseLeave={(e) => e.currentTarget.style.background = '#eff6ff'}><BadgeCheck size={13} /><span style={{ flex: 1, textAlign: 'left' }}>Endorse as department canonical version</span></button></div>}
      <div style={{ display: 'flex', alignItems: 'stretch', borderBottom: '1px solid var(--border)', flexShrink: 0, padding: '0 14px', overflowX: 'auto', gap: 2 }}>
        {TABS.map((t) => {const icons: Partial<Record<Tab, React.ElementType>> = { AI: Sparkles, Edit: Edit2, Preview: Eye, Metrics: BarChart2, Versions: Clock, Comments: MessageSquare };const Icon = icons[t];return <button key={t} onClick={() => setTab(t)} style={{ display: 'flex', alignItems: 'center', gap: 5, padding: '9px 10px', fontSize: 13, fontWeight: tab === t ? 600 : 400, color: tab === t ? 'var(--foreground)' : 'var(--text3)', borderBottom: tab === t ? '2px solid var(--foreground)' : '2px solid transparent', background: 'transparent', border: 'none', cursor: 'pointer', whiteSpace: 'nowrap', marginBottom: -1, flexShrink: 0 }}>{Icon && <Icon size={12} style={{ opacity: tab === t ? 1 : 0.6 }} />}{t}{t === 'Comments' && comments.filter((c) => !c.resolved).length > 0 && <span style={{ width: 5, height: 5, borderRadius: '50%', background: '#dc2626', display: 'inline-block' }} />}</button>;})}
      </div>
      <div style={{ flex: 1, overflowY: 'auto', padding: '16px 14px' }}>
        {tab === 'Overview' && <div><p style={{ fontSize: 15, color: 'var(--foreground)', lineHeight: 1.7, marginBottom: 14 }}>{q.stem}</p>{q.type === 'MCQ' && q.options && <div style={{ display: 'flex', flexDirection: 'column', gap: 7, marginBottom: 14 }}>{q.options.map((o, i) => {const isC = i === q.correctAnswer;return <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 9, padding: '9px 13px', borderRadius: 8, border: '1.5px solid ' + (isC ? '#16a34a' : 'var(--border-control)'), background: isC ? '#f0fdf4' : 'var(--card)' }}><div style={{ width: 15, height: 15, borderRadius: '50%', border: '2px solid ' + (isC ? '#16a34a' : 'var(--border-control)'), background: isC ? '#16a34a' : 'transparent', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>{isC && <div style={{ width: 5, height: 5, borderRadius: '50%', background: '#fff' }} />}</div><span style={{ fontSize: 13, color: 'var(--foreground)', fontWeight: isC ? 500 : 400, flex: 1 }}>{String.fromCharCode(65 + i)}) {o}</span>{isC && <span style={{ fontSize: 12, fontWeight: 600, color: '#15803d', flexShrink: 0 }}>Correct</span>}</div>;})}</div>}<div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 1, border: '1px solid var(--border)', borderRadius: 8, overflow: 'hidden', marginBottom: 12 }}>{[['Status', q.status], ['Type', q.type], ["Bloom's", q.blooms], ['Difficulty', q.difficulty], ['Author', q.owner], ['Version', 'v' + q.version], ['Used', (q.usageCount || 0) + 'x'], ['Updated', q.updatedAt || '—']].map(([l, v], i) => <div key={String(l)} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '8px 12px', borderBottom: i < 6 ? '1px solid var(--border)' : 'none', background: 'var(--card)', borderRight: i % 2 === 0 ? '1px solid var(--border)' : 'none' }}><span style={{ fontSize: 12, color: 'var(--text3)' }}>{l}</span><span style={{ fontSize: 13, fontWeight: 500, color: 'var(--text2)' }}>{String(v)}</span></div>)}</div>{q.tags && q.tags.length > 0 && <div style={{ marginBottom: 12, display: 'flex', gap: 4, flexWrap: 'wrap' }}>{q.tags.map((t) => <span key={t} style={{ padding: '2px 9px', borderRadius: 99, fontSize: 12, fontWeight: 500, background: 'var(--surface2)', color: 'var(--text2)', border: '1px solid var(--border)' }}>{t}</span>)}</div>}<button onClick={() => setTab('Edit')} style={{ width: '100%', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 5, padding: '8px', borderRadius: 8, border: '1px dashed var(--border-control)', background: 'transparent', cursor: 'pointer', fontSize: 13, color: 'var(--text2)', fontWeight: 500 }} onMouseEnter={(e) => {e.currentTarget.style.background = 'var(--surface2)';e.currentTarget.style.borderColor = 'var(--foreground)';}} onMouseLeave={(e) => {e.currentTarget.style.background = 'transparent';e.currentTarget.style.borderColor = 'var(--border-control)';}}><Edit2 size={12} />Edit this question</button></div>}
        {tab === 'Edit' && <InlineEdit q={q} onSave={(msg) => notify(msg, 'success')} />}
        {tab === 'Preview' && <StudentPreview q={q} />}
        {tab === 'Metrics' && <div><div style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em', color: 'var(--text3)', marginBottom: 12 }}>{USAGE.length} assessments - {USAGE.reduce((s, d) => s + d.n, 0)} exam takers</div><div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8, marginBottom: 14 }}>{[{ l: 'Correct %', v: '72%', s: 'latest cohort' }, { l: 'P-Biserial', v: '0.41', s: 'discrimination' }, { l: 'Disc. Index', v: '0.46', s: 'U27-L27' }, { l: 'Avg time', v: '1m 48s', s: 'per question' }].map((m) => <div key={m.l} style={{ padding: '12px 14px', borderRadius: 8, background: 'var(--surface)', border: '1px solid var(--border)' }}><div style={{ fontSize: 12, color: 'var(--text3)', marginBottom: 3 }}>{m.l}</div><div style={{ fontSize: 21, fontWeight: 700, fontFamily: 'monospace', color: 'var(--foreground)', marginBottom: 2 }}>{m.v}</div><div style={{ fontSize: 12, color: 'var(--text3)' }}>{m.s}</div></div>)}</div><div style={{ borderRadius: 8, border: '1px solid var(--border)', overflow: 'hidden' }}><div style={{ display: 'grid', gridTemplateColumns: '1fr 65px 52px 58px', padding: '8px 12px', borderBottom: '1px solid var(--border)', background: 'var(--surface)' }}>{['Assessment', 'Correct', 'P-Bis', 'Time'].map((h) => <span key={h} style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em', color: 'var(--text3)', textAlign: h === 'Assessment' ? 'left' : 'right' }}>{h}</span>)}</div>{USAGE.map((row, i) => <div key={i} style={{ display: 'grid', gridTemplateColumns: '1fr 65px 52px 58px', padding: '9px 12px', borderBottom: i < USAGE.length - 1 ? '1px solid var(--border)' : 'none', alignItems: 'center' }}><div><div style={{ fontSize: 13, fontWeight: 500, color: 'var(--foreground)' }}>{row.course}</div><div style={{ fontSize: 12, color: 'var(--text3)' }}>{row.term} n={row.n}</div></div><div style={{ textAlign: 'right', fontSize: 13, fontFamily: 'monospace', fontWeight: 600, color: '#15803d' }}>{row.correct}%</div><div style={{ textAlign: 'right', fontSize: 13, fontFamily: 'monospace', fontWeight: 600, color: row.pbis >= 0.3 ? '#15803d' : row.pbis >= 0.15 ? '#92400e' : '#991b1b' }}>{row.pbis.toFixed(2)}</div><div style={{ textAlign: 'right', fontSize: 12, color: 'var(--text3)' }}>1m 48s</div></div>)}</div></div>}
        {tab === 'Versions' && <div><div style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em', color: 'var(--text3)', marginBottom: 12 }}>Version history</div>{[{ v: q.version, editor: q.owner, date: 'Mar 14, 2026', note: 'Stem refined. Alt text added to diagram.', current: true }, { v: Math.max(q.version - 1, 1), editor: 'Dr. Kim', date: 'Jan 8, 2026', note: 'Added pharmacokinetic context.', current: false }, { v: 1, editor: q.owner, date: 'Sep 3, 2024', note: 'Initial creation.', current: false }].filter((v, i, a) => a.findIndex((x) => x.v === v.v) === i && v.v >= 1).map((v) => <div key={v.v} style={{ display: 'flex', gap: 12, padding: '12px 0', borderBottom: '1px solid var(--border)' }}><div style={{ width: 26, height: 26, borderRadius: '50%', background: v.current ? 'var(--foreground)' : 'var(--surface)', border: '1px solid var(--border)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0, fontSize: 11, fontWeight: 700, color: v.current ? 'var(--card)' : 'var(--text3)', fontFamily: 'monospace' }}>v{v.v}</div><div style={{ flex: 1 }}><div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 3 }}><span style={{ fontSize: 13, fontWeight: 500, color: 'var(--foreground)' }}>{v.editor}</span>{v.current && <span style={{ fontSize: 11, padding: '1px 6px', borderRadius: 99, background: 'var(--brand-tint)', color: 'var(--brand)', fontWeight: 600 }}>Current</span>}<span style={{ fontSize: 12, color: 'var(--text3)', marginLeft: 'auto' }}>{v.date}</span></div><div style={{ fontSize: 13, color: 'var(--text3)', lineHeight: 1.5 }}>{v.note}</div>{!v.current && <div style={{ marginTop: 5, display: 'flex', gap: 5 }}><button onClick={() => notify('Restored to v' + v.v)} style={{ fontSize: 12, padding: '3px 9px', borderRadius: 5, border: '1px solid var(--border-control)', background: 'var(--card)', cursor: 'pointer', color: 'var(--text2)' }}>Restore</button><button onClick={() => notify('Fork created from v' + v.v)} style={{ fontSize: 12, padding: '3px 9px', borderRadius: 5, border: '1px solid var(--border-control)', background: 'var(--card)', cursor: 'pointer', color: 'var(--text2)', display: 'flex', alignItems: 'center', gap: 3 }}><GitFork size={10} />Fork</button></div>}</div></div>)}</div>}
        {tab === 'Comments' && <div><div style={{ fontSize: 11, fontWeight: 700, textTransform: 'uppercase', letterSpacing: '0.05em', color: 'var(--text3)', marginBottom: 12 }}>{comments.length} comments - {comments.filter((c) => !c.resolved).length} open</div><div style={{ display: 'flex', flexDirection: 'column', gap: 9, marginBottom: 14 }}>{comments.map((comment) => <div key={comment.id} style={{ borderRadius: 8, border: '1px solid var(--border)', background: 'var(--card)', overflow: 'hidden', opacity: comment.resolved ? 0.6 : 1 }}><div style={{ display: 'flex', gap: 9, padding: '11px 13px' }}><Avatar initials={comment.initials} /><div style={{ flex: 1 }}><div style={{ display: 'flex', alignItems: 'center', gap: 7, marginBottom: 3 }}><span style={{ fontSize: 13, fontWeight: 600, color: 'var(--foreground)' }}>{comment.author}</span><span style={{ fontSize: 12, color: 'var(--text3)' }}>{comment.date}</span>{comment.resolved && <span style={{ fontSize: 11, padding: '1px 6px', borderRadius: 99, background: '#dcfce7', color: '#15803d', fontWeight: 600 }}>Resolved</span>}</div><div style={{ fontSize: 13, color: 'var(--foreground)', lineHeight: 1.6 }}>{comment.text}</div></div>{!comment.resolved && <button onClick={() => setComments((prev) => prev.map((c) => c.id === comment.id ? { ...c, resolved: true } : c))} style={{ padding: '3px 9px', borderRadius: 5, border: '1px solid var(--border-control)', background: 'transparent', fontSize: 12, cursor: 'pointer', color: 'var(--text3)', flexShrink: 0, height: 'fit-content' }}>Resolve</button>}</div></div>)}</div><div style={{ display: 'flex', gap: 7, alignItems: 'flex-start' }}><Avatar initials='RP' /><div style={{ flex: 1 }}><textarea value={newComment} onChange={(e) => setNewComment(e.target.value)} placeholder='Leave a comment...' rows={3} style={{ width: '100%', padding: '8px 11px', borderRadius: 8, border: '1px solid var(--border-control)', fontSize: 13, outline: 'none', resize: 'none', fontFamily: 'var(--font-ui)', marginBottom: 5, color: 'var(--foreground)', lineHeight: 1.55, boxSizing: 'border-box' }} /><button onClick={() => {if (newComment.trim()) {setComments((prev) => [...prev, { id: Date.now(), author: 'Dr. Romit', initials: 'RP', date: 'Now', text: newComment, resolved: false }]);setNewComment('');notify('Comment posted');}}} style={{ display: 'flex', alignItems: 'center', gap: 5, padding: '6px 13px', borderRadius: 6, background: 'var(--foreground)', color: 'var(--card)', border: 'none', fontSize: 13, fontWeight: 600, cursor: 'pointer' }}><Send size={12} />Post comment</button></div></div></div>}
        {tab === 'AI' && <div><div style={{ padding: '11px 13px', borderRadius: 8, background: 'var(--surface)', border: '1px solid var(--border)', marginBottom: 12 }}><div style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 5 }}><div style={{ width: 5, height: 5, borderRadius: '50%', background: q.pbis !== null && q.pbis < 0.15 ? '#dc2626' : '#16a34a' }} /><span style={{ fontSize: 13, fontWeight: 600, color: 'var(--foreground)' }}>{q.pbis !== null && q.pbis < 0.15 ? 'Low discriminator - review recommended' : 'Performing well'}</span><span style={{ marginLeft: 'auto', fontSize: 11, padding: '2px 6px', borderRadius: 3, background: 'var(--card)', border: '1px solid var(--border)', color: 'var(--text3)', fontWeight: 500 }}>Leo</span></div><div style={{ fontSize: 13, color: 'var(--text3)', lineHeight: 1.6 }}>{q.pbis !== null && q.pbis < 0.15 ? 'P-Biserial of ' + q.pbis?.toFixed(2) + ' is below the 0.30 threshold. Consider revising distractors or stem clarity.' : 'No immediate quality issues detected. P-Biserial trend is positive across cohorts.'}</div></div><div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 7, marginBottom: 11 }}>{[{ id: 'analyze', label: 'Analyze quality', desc: 'P-Bis + distractors' }, { id: 'improve', label: 'Suggest improvements', desc: 'Stem + distractor rewrite' }, { id: 'predict', label: 'Predict performance', desc: 'Forecast next cohort' }, { id: 'variants', label: 'Generate variants', desc: '3 levels' }].map(({ id, label, desc }) => <button key={id} onClick={() => setAiMode(id)} style={{ padding: '9px 11px', borderRadius: 8, textAlign: 'left', border: '1.5px solid ' + (aiMode === id ? 'var(--brand)' : 'var(--border-control)'), background: aiMode === id ? 'var(--brand-tint)' : 'var(--card)', cursor: 'pointer', fontFamily: 'var(--font-ui)' }}><div style={{ fontSize: 13, fontWeight: aiMode === id ? 600 : 400, color: aiMode === id ? 'var(--brand)' : 'var(--foreground)', marginBottom: 2 }}>{label}</div><div style={{ fontSize: 11, color: 'var(--text3)' }}>{desc}</div></button>)}</div><button onClick={() => runAI(aiMode)} disabled={aiLoading} style={{ display: 'flex', alignItems: 'center', gap: 5, padding: '7px 14px', borderRadius: 8, background: 'var(--foreground)', color: 'var(--card)', border: 'none', cursor: aiLoading ? 'default' : 'pointer', fontSize: 13, fontWeight: 600, marginBottom: 11, opacity: aiLoading ? 0.5 : 1 }}><Sparkles size={13} />{aiLoading ? 'Analysing...' : 'Run Leo'}</button>{aiResult && <div style={{ padding: '11px 13px', borderRadius: 8, background: 'var(--surface)', border: '1px solid var(--border)', lineHeight: 1.7, fontSize: 13, color: 'var(--foreground)', whiteSpace: 'pre-line' }}><div style={{ fontSize: 10, fontWeight: 700, color: 'var(--text3)', marginBottom: 5, textTransform: 'uppercase', letterSpacing: '0.05em' }}>Leo result</div>{aiResult}</div>}</div>}
      </div>
    </div>);

}